import React, { useState, useRef, useLayoutEffect } from 'react';
import { GridContent } from '@ant-design/pro-layout';
import { Menu, theme } from 'antd';
import styles from './style.less';
import { t } from '../../../global';
import { SignedDevices } from './components/signedDevices';
import UserSettingsView from './components/userSettings';
import makeSecuritySettingsComponent from './components/security/security';
import makeGeneralSettingsComponent from './components/base/general';

const { Item } = Menu;
const { useToken } = theme;

type SettingsState = {
  mode: 'inline' | 'horizontal';
  selectKey: string;
};

const Settings: React.FC = () => {
  const menuMap: Record<string, React.ReactNode> = {
    base: t('Basic Settings'),
    security: t('Security Settings'),
    signedDevices: t('Manage Signed Devices'),
  };

  const [initConfig, setInitConfig] = useState<SettingsState>({
    mode: 'inline',
    selectKey: 'base',
  });
  const dom = useRef<HTMLDivElement>();
  const { token } = useToken();

  useLayoutEffect(() => {
    const resize = () => {
      requestAnimationFrame(() => {
        if (!dom.current) {
          return;
        }
        let mode: 'inline' | 'horizontal' = 'inline';
        const { offsetWidth } = dom.current;
        if (dom.current.offsetWidth < 641 && offsetWidth > 400) {
          mode = 'horizontal';
        }
        if (window.innerWidth < 768 && offsetWidth > 400) {
          mode = 'horizontal';
        }
        if (mode !== initConfig.mode) {
          setInitConfig({ ...initConfig, mode: mode as SettingsState['mode'] });
        }
      });
    };

    if (dom.current) {
      window.addEventListener('resize', resize);
      resize();
    }
    return () => {
      window.removeEventListener('resize', resize);
    };
  }, [initConfig]);

  const getMenu = () => {
    return Object.keys(menuMap).map((item) => <Item key={item}>{menuMap[item]}</Item>);
  };

  const renderChildren = () => {
    const { selectKey } = initConfig;
    switch (selectKey) {
      case 'base':
        return <UserSettingsView componentCreator={makeGeneralSettingsComponent} handleSwitchTab={(tab: string) => {
          setInitConfig({
            ...initConfig,
            selectKey: tab,
          });
        }} />;
      case 'security':
        return <UserSettingsView componentCreator={makeSecuritySettingsComponent} />;
      case 'signedDevices':
        return <SignedDevices />;
      default:
        return null;
    }
  };

  return (
    <GridContent>
      <div
        className={styles.main}
        style={{ backgroundColor: token.colorBgContainer }}
        ref={(ref) => {
          if (ref) {
            dom.current = ref;
          }
        }}
      >
        <div className={styles.leftMenu}>
          <Menu
            style={{ height: '100%' }}
            mode={initConfig.mode}
            selectedKeys={[initConfig.selectKey]}
            onClick={({ key }) => {
              setInitConfig({
                ...initConfig,
                selectKey: key,
              });
            }}
          >
            {getMenu()}
          </Menu>
        </div>
        <div className={styles.right}>
          <div className={styles.title}>{menuMap[initConfig.selectKey]}</div>
          {renderChildren()}
        </div>
      </div>
    </GridContent>
  );
};

export default Settings;
