import React, { useState } from 'react';
import { Avatar, Button, Modal, Popconfirm, Tooltip, Upload, message } from 'antd';
import ProForm, { ProFormCheckbox, ProFormText } from '@ant-design/pro-form';
import { EmailEditor, ThirdAuthTypeTag } from '@/pages/UserList';
import { deleteUserAvatar, updateUser, uploadUserAvatar } from '@/services/api';
import { extractApiErrorMessage, t } from '@/global';
import type { API } from '@/services/typings';
import { IsTfaVerificationError, TfaCodeComponent, TfaComponent } from '../tfa/tfa';
import { DeleteOutlined, QuestionCircleOutlined, UploadOutlined } from '@ant-design/icons';
import styles from './general.less';
import { isTfaEnabled, type UserSettingsProps } from '../userSettings';
import { useIntl } from 'umi';

// Client-side pre-check only to avoid reading extremely large files into memory.
// Avatar upload is a low-frequency operation, and the server remains the source
// of truth for size limits (it returns a concrete "max XX KB" error message).
// We intentionally keep this frontend guard simple for now and do not introduce
// an extra API just to sync MAX_AVATAR_MB dynamically.
const MAX_AVATAR_FILE_BYTES = 20 * 1024 * 1024;

type CheckEmailModalProps = {
    email: string;
    onClosed: () => void;
}

const CheckEmailModal: React.FC<CheckEmailModalProps> = ({ email, onClosed }) => {
    return <>
        <Modal
            title={t('Check your email')}
            open={true}
            onCancel={onClosed}
            onOk={onClosed}
            okText={t('OK')}
            cancelText={t('Cancel')}
            cancelButtonProps={{ style: { display: 'none' } }}
        >
            <div className={styles.checkEmail}>
                <div className={styles.checkEmailContainer}>
                    <div className={styles.emailIcon}>
                        <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 48 48">
                            <g fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="4">
                                <path d="M36 15h8v26H4V15h8m12 4V5" />
                                <path d="m30 13l-6 6l-6-6" />
                                <path d="m4 15l20 15l20-15" />
                            </g>
                        </svg>
                    </div>
                    <div className={styles.desc}>
                        <div>
                            {t('We\'ve sent an email with a verification link to ')}
                            <span className={styles.descEmail}>{email}</span>
                            <br />
                            <br />
                            {t('Please check your inbox and click the link to complete the update.')}
                        </div>
                    </div>
                </div>
            </div>
        </Modal>
    </>;
}

type SettingsGeneralProps = {
    currentUser: API.User | undefined;
    refreshInitialState: () => Promise<void>;
}

export const SettingsGeneral: React.FC<SettingsGeneralProps> = ({ currentUser, refreshInitialState }) => {
    const intl = useIntl();
    const [form] = ProForm.useForm<API.User | undefined>();
    const [isDisplayNameChanged, setIsDisplayNameChanged] = useState<boolean>(false);
    const [isEmailVerificationChanged, setIsEmailVerificationChanged] = useState<boolean>(false);
    const [isEmailAlarmNotificationChanged, setIsEmailAlarmNotificationChanged] = useState<boolean>(false);
    const [isAvatarUploading, setIsAvatarUploading] = useState<boolean>(false);
    const [tfaErr, setTfaErr] = useState<string | undefined>(undefined);
    const [newEmail, setNewEmail] = useState<string>('');
    const [isCheckEmailModalOpen, setIsCheckEmailModalOpen] = useState<boolean>(false);

    const statusTfa = currentUser?.status_tfa;
    const isEmailChanged = newEmail.length != 0 && newEmail != currentUser?.email;
    const displayName = currentUser?.display_name || currentUser?.name || '';
    const trimmedDisplayName = displayName.trim();
    const shownInitial = trimmedDisplayName ? trimmedDisplayName[0] : '?';

    const handleFinish = async (value: any) => {
        if ('display_name' in value) {
            const displayName = (value.display_name ?? '').trim();
            value.display_name = displayName;
            if (displayName === (currentUser?.display_name ?? '')) {
                delete value.display_name;
            }
        }
        const email = (value.email ?? '').trim();
        const currentEmail = (currentUser?.email ?? '').trim();
        if ('email' in value) {
            value.email = email;
        }
        // email invalid
        if (!email) {
            if (value.info?.email_verification) {
                message.error("A valid email address is required to enable email login verification.");
                return;
            }
            // if (value.info?.email_alarm_notification) {
            //   message.error("A valid email address is required to enable alarm event email notification.");
            //   return;
            // }
        }
        if (email === currentEmail) {
            delete value.email;
        }
        if (value.info) {
            if (!!value.info?.email_verification == !!currentUser?.info?.email_verification) {
                delete value.info.email_verification;
            }
            if (!!value.info?.email_alarm_notification == !!currentUser?.info?.email_alarm_notification) {
                delete value.info.email_alarm_notification;
            }
            if (Object.keys(value.info).length == 0) {
                delete value.info;
            }
        }
        if (Object.keys(value).length == 0) {
            message.error(t("No changes have been made."));
            return;
        }

        const updateEmailOnly = Object.keys(value).length == 1 && value.email;

        const hide = message.loading(t('Updating'));
        try {
            const res = await updateUser({ data: value });
            hide();
            if (!updateEmailOnly) {
                message.success(t('Update successfully!'));
            }
            await refreshInitialState();
            if (res.verification_email_sent) {
                setIsCheckEmailModalOpen(true);
            }
            form.setFieldValue('email', currentUser?.email ?? '');
            setIsDisplayNameChanged(false);
            setIsEmailVerificationChanged(false);
            setIsEmailAlarmNotificationChanged(false);
            return true;
        } catch (error) {
            hide();
            form.setFieldValue('email', currentUser?.email ?? '');
            if (typeof error == 'string') {
                if (IsTfaVerificationError(error)) {
                    setTfaErr(error);
                } else {
                    message.error(error);
                }
            } else {
                message.error(t('Update failed, please try again!'));
            }
            return false;
        }
    };

    const onEmailChange = (value: string) => setNewEmail(value);
    const onDisplayNameChange = (value: string) => {
        const newDisplayName = (value ?? '').trim();
        const oldDisplayName = (currentUser?.display_name ?? '').trim();
        setIsDisplayNameChanged(newDisplayName != oldDisplayName);
    };
    const onEmailVerificationChange = (value: boolean) => setIsEmailVerificationChanged(value != (currentUser?.info?.email_verification ?? false));
    const onEmailAlarmNotificationChange = (value: boolean) => setIsEmailAlarmNotificationChanged(value != (currentUser?.info?.email_alarm_notification ?? false));

    const fileToBase64 = (file: File): Promise<string> => new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve((reader.result as string) || '');
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });

    const handleUploadAvatar = async (file: File) => {
        if (isAvatarUploading) {
            return;
        }
        const allowedType = ['image/png', 'image/jpeg', 'image/jpg', 'image/webp', 'image/gif'].includes(file.type);
        if (!allowedType) {
            message.error(t('Only png/jpg/webp/gif avatar images are supported.', true, '', intl));
            return;
        }
        if (file.size > MAX_AVATAR_FILE_BYTES) {
            message.error(t('Avatar image is too large, max 20 MB.', true, '', intl));
            return;
        }
        setIsAvatarUploading(true);
        try {
            const dataUrl = await fileToBase64(file);
            const dataBase64 = dataUrl.includes(',') ? dataUrl.split(',')[1] : dataUrl;
            await uploadUserAvatar({ data_base64: dataBase64, mime_type: file.type });
            message.success(t('Update successfully!'));
            await refreshInitialState();
        } catch (e) {
            const errMsg = extractApiErrorMessage(e);
            message.error(errMsg || t('Update failed, please try again!'));
        } finally {
            setIsAvatarUploading(false);
        }
    };

    const handleDeleteAvatar = async () => {
        if (isAvatarUploading) {
            return;
        }
        setIsAvatarUploading(true);
        try {
            await deleteUserAvatar();
            message.success(t('Update successfully!'));
            await refreshInitialState();
        } catch (e) {
            const errMsg = extractApiErrorMessage(e);
            message.error(errMsg || t('Update failed, please try again!'));
        } finally {
            setIsAvatarUploading(false);
        }
    };

    return <>
        {isCheckEmailModalOpen && <CheckEmailModal email={newEmail} onClosed={() => {
            setIsCheckEmailModalOpen(false);
            setNewEmail('');
        }} />}
        <ProForm<API.User | undefined>
            layout="vertical"
            onFinish={handleFinish}
            labelCol={{ span: 24, offset: 0 }} labelAlign={"left"}
            submitter={{
                resetButtonProps: {
                    style: {
                        display: 'none',
                    },
                },
                submitButtonProps: {
                    children: t('Update'),
                },
            }}
            initialValues={{
                ...currentUser,
            }}
            requiredMark={false}
            form={form}
        >
            <ProForm.Item>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <Avatar size={64} src={currentUser?.avatar} style={{ backgroundColor: '#1677ff', color: '#fff' }}>
                        {shownInitial}
                    </Avatar>
                    <Upload
                        showUploadList={false}
                        accept="image/png,image/jpeg,image/webp,image/gif,.jpg,.jpeg"
                        disabled={isAvatarUploading}
                        beforeUpload={(file) => {
                            if (isAvatarUploading) {
                                return Upload.LIST_IGNORE;
                            }
                            handleUploadAvatar(file as File);
                            return Upload.LIST_IGNORE;
                        }}
                    >
                        <Button icon={<UploadOutlined />} loading={isAvatarUploading} disabled={isAvatarUploading}>
                            {t('Change avatar', true)}
                        </Button>
                    </Upload>
                    {!!currentUser?.avatar && <Popconfirm
                        disabled={isAvatarUploading}
                        title={t('Delete avatar', true)}
                        onConfirm={handleDeleteAvatar}
                        okText={t('OK')}
                        cancelText={t('Cancel')}
                    >
                        <Button icon={<DeleteOutlined />} danger loading={isAvatarUploading} disabled={isAvatarUploading}>
                            {t('Delete', true)}
                        </Button>
                    </Popconfirm>}
                </div>
            </ProForm.Item>
            <ProFormText
                width="md"
                name="display_name"
                fieldProps={{ onChange: (e: any) => onDisplayNameChange(e.target.value) }}
                rules={[
                    {
                        max: 300,
                    },
                ]}
                label={t('Display Name', true)}
            />
            <EmailEditor onChange={onEmailChange} />
            <ProFormCheckbox
                name={["info", "email_verification"]}
                disabled={isTfaEnabled(statusTfa)}
                fieldProps={{ onChange: (e: any) => onEmailVerificationChange(e.target.checked) }}
            >
                {t("Enable email login verification")}
                {isTfaEnabled(statusTfa) && <Tooltip title={t('Since 2FA is enabled, the email login verification option is not used. 2FA login verification will be used instead.')}>
                    <QuestionCircleOutlined style={{ marginLeft: '6px', color: 'gray', cursor: 'help' }} />
                </Tooltip>}
            </ProFormCheckbox>
            <ProFormCheckbox
                name={["info", "email_alarm_notification"]}
                fieldProps={{ onChange: (e: any) => onEmailAlarmNotificationChange(e.target.checked) }}
            >
                {t("Enable alarm event email notification")}
            </ProFormCheckbox>
            {
                (isDisplayNameChanged || isEmailChanged || isEmailVerificationChanged || isEmailAlarmNotificationChanged) &&
                isTfaEnabled(statusTfa) && <TfaCodeComponent form={form} isBackupCodeAcceptable={true} err={tfaErr} setErr={setTfaErr} />
            }
        </ProForm>
    </>;
}

export const UserInfo: React.FC<UserSettingsProps> = ({ currentUser, refreshInitialState, handleSwitchTab }) => {
    const displayName = currentUser?.display_name || currentUser?.name;
    return <>
        <ProForm.Item style={{ marginTop: '-15px', marginLeft: '3px' }}>
            <div className={styles.title}>
                <div className={styles.titleUsername}>
                    <label>{displayName}</label>
                </div>
                {
                    currentUser?.third_auth_type != undefined && <div style={{ marginLeft: '10px' }}>
                        {ThirdAuthTypeTag(currentUser?.third_auth_type)}
                    </div>
                }
            </div>
            {/* marginTop won't overlap because .title has padding-bottom: 18px, so -16px still leaves 2px gap */}
            {currentUser?.display_name && <div style={{ color: '#999', marginTop: '-16px', marginBottom: '13px' }}>@{currentUser?.name}</div>}
            <div style={{ paddingBottom: '5px' }}>
                <TfaComponent
                    currentUser={currentUser}
                    handleSwitchSecurity={() => handleSwitchTab?.('security')}
                    refreshInitialState={refreshInitialState}
                />
            </div>
        </ProForm.Item>
    </>;
}

const makeGeneralSettingsComponent = ({ currentUser, refreshInitialState, handleSwitchTab }: UserSettingsProps) => <>
    <UserInfo currentUser={currentUser} refreshInitialState={refreshInitialState} handleSwitchTab={handleSwitchTab} />
    <SettingsGeneral
        currentUser={currentUser}
        refreshInitialState={refreshInitialState}
    />
</>;

export default makeGeneralSettingsComponent;
