import { useEffect, useState } from "react";
import type { API } from "@/services/typings";
import { userSessions, deleteUserSession } from "@/services/api";
import { List, message, Spin, Tag } from "antd";
import { QuestionOutlined } from "@ant-design/icons";
import { formatYMDHMFromTimestamp, get_os_svg, keyAccessToken, t } from "@/global";

export const SignedDevices: React.FC = () => {
    const [sessions, setSessions] = useState<API.UserSession[] | undefined>(undefined);
    const myid = localStorage.getItem(keyAccessToken) || sessionStorage.getItem(keyAccessToken);

    async function fetchSessions() {
        const uSessions = await userSessions();
        const sortedSessions = uSessions.sort((a, b) => {
            const aExpiration = (a.expiry_at || 0) - (a.ttl_secs || 0);
            const bExpiration = (b.expiry_at || 0) - (b.ttl_secs || 0);
            return bExpiration - aExpiration;
        });
        setSessions(sortedSessions);
    }

    useEffect(() => {
        fetchSessions();
    }, []);

    if (sessions == undefined) return <div style={{width: '100%', textAlign: "center"}}><Spin /></div>;

    return (<List<API.UserSession>
        bordered
        itemLayout="horizontal"
        dataSource={sessions}
        pagination={{
            pageSize: 5
        }}
        size="small"
        renderItem={(item) => (
            <List.Item
                actions={item.id != myid ? [<a key={item.id} onClick={async () => {
                    try {
                        await deleteUserSession({ data: { id: item.id } });
                        message.success("Delete session success");
                        fetchSessions();
                    } catch (error) {
                        message.error("Failed to delete session: " + error);
                    }
                }}>{t("Logout")}</a>] : undefined}
            >
                <List.Item.Meta
                    avatar={get_avatar(item) ?? <QuestionOutlined />}
                    title={<>
                        {item.device_info?.name ?? t("Unknown")}
                        {item.id == myid ? <Tag style={{ marginLeft: "10px" }} color="blue">{t("Current session")}</Tag> : undefined}
                    </>}
                    description={
                        <>
                            <table>
                                <tbody>
                                    {
                                        item.created_at && formatYMDHMFromTimestamp(item.created_at) !== get_updated_time(item) ? <tr>
                                            <td>{t('First sign-in:')}</td>
                                            <td>{formatYMDHMFromTimestamp(item.created_at)}</td>
                                        </tr> : undefined
                                    }
                                    <tr>
                                        <td>{t('Recent activity:')}</td>
                                        <td>{get_updated_time(item)}</td>
                                    </tr>
                                    <tr>
                                        <td>IP:</td>
                                        <td>{item.ip?.replace("::ffff:", "")}</td>
                                    </tr>
                                </tbody>
                            </table>                       </>
                    }
                />
            </List.Item>
        )}
    />)
}

function get_avatar(item: API.UserSession) {
    if (item.device_info?.os) {
        return get_os_svg("2em", item.device_info.os);
    }
    return;
}

function get_updated_time(item: API.UserSession): string | undefined {
    if (item.expiry_at && item.ttl_secs) {
        const updated_at = item.expiry_at - item.ttl_secs;
        return formatYMDHMFromTimestamp(updated_at);
    }
    return;
}

