import React, { useState } from 'react';
import styles from './security.less';
import { EnableTfaAction, IsTfaVerificationError, TfaCodeComponent } from '../tfa/tfa';
import { useIntl, useModel } from '@umijs/max';
import { t } from '@/global';
import { UserPassword } from '@/pages/UserList';
import { ModalForm } from '@ant-design/pro-form';
import { updateUser, userTfaDisable, userTfaGetBackupCodes } from '@/services/api';
import { Button, Divider, Form, Space, message, Modal } from 'antd';
import { getBackupCodesDesc, makeBackupCodesComponents, makeBackupCodesSubmitter } from '../tfa/BackupCodes';
import { isTfaEnabled, SettingsActionTooltipIcon, type UserSettingsProps } from '../userSettings';
import { loginOut } from '@/components/RightContent/AvatarDropdown';

enum ChangePasswordState {
    Change = 0,
    Logout = 1,
}

type ChangePasswordActionProps = {
    statusTfa?: number,
    plain: (text: string, defaultMessage?: string) => string;
}

const ChangePasswordAction: React.FC<ChangePasswordActionProps> = ({ statusTfa, plain }) => {
    const [form] = Form.useForm();
    const { setInitialState } = useModel('@@initialState');
    const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
    const [changePasswordState, setChangePasswordState] = useState<ChangePasswordState>(ChangePasswordState.Change);
    const [tfaErr, setTfaErr] = useState<string | undefined>(undefined);

    const showModal = () => {
        setChangePasswordState(ChangePasswordState.Change);
        setIsModalOpen(true);
    };

    const handleSubmit = async (values: any) => {
        if (changePasswordState === ChangePasswordState.Change) {
            try {
                // Copy values and remove confirm-password field
                const { 'confirm-password': _, ...submitData } = values;
                await updateUser({ data: submitData });
                setChangePasswordState(ChangePasswordState.Logout);
            } catch (error: any) {
                if (typeof error == 'string' && IsTfaVerificationError(error)) {
                    setTfaErr(error);
                } else {
                    message.error(error);
                }
            }
        } else {
            try {
                setInitialState((s) => ({ ...s, user: undefined }));
                loginOut({ 'users': '' });
                setIsModalOpen(false);
            } catch (error: any) {
                message.error(error);
            }
        }
    }

    const changepasswordContent = () => <>
        <UserPassword required={true} autoFocus={true} />
        {
            isTfaEnabled(statusTfa) && <TfaCodeComponent form={form} isBackupCodeAcceptable={true} err={tfaErr} setErr={setTfaErr} />
        }
    </>;

    const logoutContent = () => <>
        <div className={styles.logout}>
            {plain('Your password has been changed. Would you like to log out of all current sessions?')}
        </div>
    </>;

    const getLogoutSubmitter = () => {
        return {
            render: (props: any, dom: JSX.Element[]) => {
                return <Space>
                    {dom[0]}
                    <Button
                        type='primary'
                        onClick={() => props.form.submit()}
                        className={styles.submitButton}
                    >
                        {plain('Logout')}
                    </Button>
                </Space>;
            },
        }
    };

    return <>
        <div className={styles.action}><a onClick={showModal}>{plain('Change password')}</a></div>
        {isModalOpen && <ModalForm
            form={form}
            title={plain('Change password')}
            width="380px"
            onFinish={handleSubmit}
            open={isModalOpen}
            onOpenChange={(v) => {
                if (!v) {
                    form.setFieldsValue({ password: '', 'confirm-password': '', tfa_code: '' });
                }
                setIsModalOpen(v);
            }}
            submitter={changePasswordState === ChangePasswordState.Change ? undefined : getLogoutSubmitter()}
        >
            {changePasswordState == ChangePasswordState.Change ? changepasswordContent() : logoutContent()}
        </ModalForm>
        }
    </>;
}

enum Display2FABackupCodesState {
    Verify = 0,
    Display = 1,
}

const Display2FABackupCodesAction: React.FC<{ plain: (text: string, defaultMessage?: string) => string }> = ({ plain }) => {
    const [form] = Form.useForm();
    const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
    const [displayState, setDisplayState] = useState<Display2FABackupCodesState>(Display2FABackupCodesState.Verify);
    const [backupCodes, setBackupCodes] = useState<string[]>([]);
    const [err, setErr] = useState<string | undefined>(undefined);

    const showModal = () => {
        setIsModalOpen(true);
    };

    const handleVerify = async (values: any) => {
        try {
            setBackupCodes(await userTfaGetBackupCodes(values));
            setDisplayState(Display2FABackupCodesState.Display);
        } catch (error: any) {
            setErr(error);
        }
    }

    const submitterRender = () => {
        if (displayState === Display2FABackupCodesState.Verify) {
            return {
                render: (props: any, dom: JSX.Element[]) => {
                    return <Space>
                        {dom[0]}
                        <Button
                            type='primary'
                            onClick={() => props.form.submit()}
                            className={styles.submitButton}
                        >
                            {plain('View backup codes')}
                        </Button>
                    </Space>;
                },
            }
        } else {
            return makeBackupCodesSubmitter(plain, backupCodes, setIsModalOpen);
        }
    };

    return <>
        <div className={styles.action}>
            <a onClick={showModal}>{plain('View backup codes')}</a>
            {SettingsActionTooltipIcon(getBackupCodesDesc(plain))}
        </div>
        {isModalOpen && <ModalForm
            form={form}
            title={plain('View backup codes')}
            width={displayState == Display2FABackupCodesState.Verify ? '380px' : '620px'}
            open={isModalOpen}
            onOpenChange={(v) => {
                if (!v) {
                    form.setFieldsValue({ tfa_code: '' });
                }
                setIsModalOpen(v);
            }}
            submitter={submitterRender()}
            onFinish={handleVerify}
        >
            {
                displayState == Display2FABackupCodesState.Verify ? <>
                    <div>
                        {plain('Enter your 2FA code to view your 2FA backup codes.')}
                    </div>
                    <TfaCodeComponent
                        form={form}
                        isBackupCodeAcceptable={false}
                        autoFocus={true}
                        err={err}
                        setErr={setErr}
                    />
                </> : <>
                    {makeBackupCodesComponents(plain, backupCodes)}
                </>
            }
        </ModalForm>
        }
    </>;
}

type Disable2FAActionProps = {
    plain: (text: string, defaultMessage?: string) => string;
    refreshInitialState: () => Promise<void>;
}

const Disable2FAAction: React.FC<Disable2FAActionProps> = ({ plain, refreshInitialState }) => {
    const [form] = Form.useForm();
    const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState<boolean>(false);
    const [err, setErr] = useState<string | undefined>(undefined);
    const { initialState } = useModel('@@initialState');
    const isTfaEnforced = initialState?.user?.info?.tfa_enforced;

    const showModal = () => {
        if (isTfaEnforced) {
            setIsConfirmModalOpen(true);
        } else {
            setIsModalOpen(true);
        }
    };

    const handleConfirmDisable = () => {
        setIsConfirmModalOpen(false);
        setIsModalOpen(true);
    };

    const handleSubmit = async (values: any) => {
        try {
            await userTfaDisable(values);
            setIsModalOpen(false);
            message.success(plain('2FA disabled successfully!'));
            refreshInitialState();
            return true;
        } catch (error: any) {
            setErr(error);
            return false;
        }
    }

    return <>
        <div className={styles.action}>
            <a onClick={showModal} style={{ color: 'red' }}>{plain('Disable')}</a>
            {SettingsActionTooltipIcon(plain('Feel free to test. You can enable it again at any time.'))}
        </div>
        {isConfirmModalOpen && <Modal
            title={t('confirm_disable_2fa_title')}
            open={isConfirmModalOpen}
            onCancel={() => setIsConfirmModalOpen(false)}
            footer={[
                <Button key="cancel" onClick={() => setIsConfirmModalOpen(false)}>
                    {t('Cancel')}
                </Button>,
                <Button key="continue" type="primary" onClick={handleConfirmDisable}>
                    {t('Continue')}
                </Button>,
            ]}
        >
            <p>{t('confirm_disable_2fa_tip')}</p>
        </Modal>
        }
        {isModalOpen && <ModalForm
            form={form}
            title={plain('Disable 2FA')}
            width="380px"
            onFinish={handleSubmit}
            open={isModalOpen}
            onOpenChange={(v) => {
                if (!v) {
                    form.setFieldsValue({ tfa_code: '' });
                }
                setIsModalOpen(v);
            }}
        >
            <TfaCodeComponent
                form={form}
                isBackupCodeAcceptable={true}
                err={err}
                setErr={setErr}
            />
        </ModalForm>
        }
    </>;
}

type TfaSettingsProps = {
    statusTfa?: number;
    refreshInitialState: () => Promise<void>;
}

const TfaSettings: React.FC<TfaSettingsProps> = ({ statusTfa, refreshInitialState }) => {
    const intl = useIntl();
    const plain = (text: string, defaultMessage = '') => t(`pages.account.tfa.${text}`, true, defaultMessage || text, intl) as string;

    const makeEnableTfaComponent = () => <div className={styles.item}>
        <div className={styles.title}>{plain('2FA')}</div>
        <div><EnableTfaAction plain={plain} className={styles.action} refreshInitialState={refreshInitialState} /></div>
    </div>;

    const makeTfaSettingsComponent = () => <>
        <div className={styles.item}>
            <div className={styles.title}>{plain('2FA')}</div>
            <div style={{ display: 'flex' }}>
                <Display2FABackupCodesAction plain={plain} />
                <Disable2FAAction plain={plain} refreshInitialState={refreshInitialState} />
            </div>
        </div>
    </>;

    return isTfaEnabled(statusTfa) ? makeTfaSettingsComponent() : makeEnableTfaComponent();
}

const SettingsSecurity: React.FC<UserSettingsProps> = ({ currentUser, refreshInitialState }) => {
    const statusTfa = currentUser?.status_tfa;
    const { initialState } = useModel('@@initialState');
    const settingsList = initialState?.settings || [];

    const intl = useIntl();
    const plain = (text: string, defaultMessage = '') => t(`pages.account.Settings.Security.${text}`, true, defaultMessage || text, intl) as string;

    const thirdAuthType = currentUser?.third_auth_type;
    const isLdapUser = thirdAuthType === 'LDAP';
    const isIdpNotLdapUser = !!thirdAuthType && !isLdapUser;
    const idpAllowLocalPasswordLoginValue = settingsList?.find((entry) => entry.key === 'IDP_ALLOW_LOCAL_PASSWORD_LOGIN')?.value;
    const idpAllowLocalPasswordLogin = idpAllowLocalPasswordLoginValue === 'TRUE' || idpAllowLocalPasswordLoginValue === 'Y';
    const showPasswordSection = !isLdapUser && (!isIdpNotLdapUser || idpAllowLocalPasswordLogin);

    const makeBaseComponent = () => <div className={styles.item}>
        <div className={styles.title}>{plain('Password')} </div>
        <ChangePasswordAction statusTfa={statusTfa} plain={plain} />
    </div>;

    return <div className={styles.security}>
        {showPasswordSection && <>
            {makeBaseComponent()}
            <Divider />
        </>}
        <TfaSettings
            statusTfa={statusTfa}
            refreshInitialState={refreshInitialState}
        />
    </div>;
}

const makeSecuritySettingsComponent = ({ currentUser, refreshInitialState }: UserSettingsProps) => <>
    <SettingsSecurity
        currentUser={currentUser}
        refreshInitialState={refreshInitialState}
    />
</>;

export default makeSecuritySettingsComponent;
